1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Customer = {
9	  yearsWithMHPCO: number;
10	};
11	
12	export type Damage = {
13	  itemType: string;
14	  amount: number;
15	};
16	
17	export type Incident = {
18	  cause: string;
19	  damages: Damage[];
20	};
21	
22	export type QuoteStep = {
23	  op: 'quote';
24	  items: Item[];
25	};
26	
27	export type ClaimStep = {
28	  op: 'claim';
29	  policy: number;
30	  incident: Incident;
31	};
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export type Scenario = {
36	  customer: Customer;
37	  steps: Step[];
38	};
39	
40	export type QuoteResult = { premium: number };
41	export type ClaimResult = { payout: number; remainingCap: number };
42	export type StepResult = QuoteResult | ClaimResult;
43	
44	type MainItemSpec = { insuranceValue: number; basePremium: number };
45	
46	const MAIN_ITEMS: Record<string, MainItemSpec> = {
47	  sword: { insuranceValue: 1000, basePremium: 100 },
48	  amulet: { insuranceValue: 600, basePremium: 60 },
49	  staff: { insuranceValue: 800, basePremium: 80 },
50	  potion: { insuranceValue: 400, basePremium: 40 },
51	};
52	
53	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
54	const COMPONENT_INSURANCE_VALUE = 250;
55	const COMPONENT_BASE_PREMIUM = 25;
56	const COMPONENT_BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PREMIUM = 60;
58	
59	const DEDUCTIBLE = 100;
60	const PROCESSING_FEE = 5;
61	
62	function isComponent(type: string): boolean {
63	  return COMPONENT_TYPES.has(type);
64	}
65	
66	function isKnownType(type: string): boolean {
67	  return type in MAIN_ITEMS || isComponent(type);
68	}
69	
70	function itemInsuranceValue(item: Item): number {
71	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].insuranceValue;
72	  if (isComponent(item.type)) return COMPONENT_INSURANCE_VALUE;
73	  throw new Error(`Unknown item type: ${item.type}`);
74	}
75	
76	function itemBasePremium(item: Item): number {
77	  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].basePremium;
78	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
79	  throw new Error(`Unknown item type: ${item.type}`);
80	}
81	
82	function componentGroupPremium(count: number): number {
83	  // Block discount applies only when there are exactly 3 alike components.
84	  // For any other count, each component is priced at the regular base premium.
85	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
86	  return count * COMPONENT_BASE_PREMIUM;
87	}
88	
89	function computePolicyBasePremium(items: Item[]): number {
90	  // Sum of item base premiums (with component block discount), no item modifiers
91	  const componentCounts = new Map<string, number>();
92	  let total = 0;
93	
94	  for (const item of items) {
95	    if (isComponent(item.type)) {
96	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
97	    } else {
98	      total += itemBasePremium(item);
99	    }
100	  }
101	
102	  for (const [, count] of componentCounts) {
103	    total += componentGroupPremium(count);
104	  }
105	
106	  return total;
107	}
108	
109	function computeItemSurcharges(items: Item[]): number {
110	  // Per-item modifiers: cursed (50% of item base), high enchantment (30% of item base)
111	  // Components in the spec examples are plain — they have no enchantment/cursed.
112	  let surcharges = 0;
113	  for (const item of items) {
114	    if (isComponent(item.type)) continue;
115	    const base = itemBasePremium(item);
116	    if (item.cursed) surcharges += base * 0.5;
117	    if ((item.enchantment ?? 0) >= 5) surcharges += base * 0.3;
118	  }
119	  return surcharges;
120	}
121	
122	export function quotePremium(
123	  items: Item[],
124	  customer: Customer,
125	  contractIndex: number,
126	): number {
127	  for (const item of items) {
128	    if (!isKnownType(item.type)) {
129	      throw new Error(`Unknown item type: ${item.type}`);
130	    }
131	  }
132	
133	  const policyBase = computePolicyBasePremium(items);
134	  const itemSurcharges = computeItemSurcharges(items);
135	
136	  let premium = policyBase + itemSurcharges;
137	
138	  if (customer.yearsWithMHPCO >= 2) {
139	    premium -= policyBase * 0.2;
140	  }
141	  // First insurance always applies (each item treated as first insurance)
142	  premium += policyBase * 0.1;
143	
144	  if (contractIndex >= 1) {
145	    premium -= policyBase * 0.15;
146	  }
147	
148	  premium += PROCESSING_FEE;
149	
150	  return Math.ceil(premium);
151	}
152	
153	export type Policy = {
154	  items: Item[];
155	  insuranceSum: number;
156	  cap: number;
157	  remainingCap: number;
158	};
159	
160	export function createPolicy(items: Item[]): Policy {
161	  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
162	  const cap = insuranceSum * 2;
163	  return { items: [...items], insuranceSum, cap, remainingCap: cap };
164	}
165	
166	function findItemForDamage(policy: Policy, itemType: string, usedIndices: Set<number>): number {
167	  for (let i = 0; i < policy.items.length; i++) {
168	    if (usedIndices.has(i)) continue;
169	    if (policy.items[i].type === itemType) return i;
170	  }
171	  return -1;
172	}
173	
174	function rawReimbursementForDamage(item: Item, damageAmount: number): number {
175	  // When both clauses apply (dragon-material AND enchantment >= 8), the 50% rule wins.
176	  // Spec: "both clauses apply; the 50 % rule wins".
177	  const isDragon = item.material === 'dragon';
178	  const isHighEnchant = (item.enchantment ?? 0) >= 8;
179	
180	  if (isHighEnchant) return damageAmount * 0.5;
181	  if (isDragon) return damageAmount;
182	  return damageAmount;
183	}
184	
185	export function processClaim(policy: Policy, incident: Incident): number {
186	  for (const dmg of incident.damages) {
187	    if (dmg.amount < 0) {
188	      throw new Error(`Negative damage amount: ${dmg.amount}`);
189	    }
190	    if (!isKnownType(dmg.itemType)) {
191	      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
192	    }
193	  }
194	
195	  // Each damage entry consumes one matching policy item instance
196	  const usedIndices = new Set<number>();
197	  const matched: Array<{ item: Item; amount: number }> = [];
198	
199	  for (const dmg of incident.damages) {
200	    const idx = findItemForDamage(policy, dmg.itemType, usedIndices);
201	    if (idx === -1) {
202	      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
203	    }
204	    usedIndices.add(idx);
205	    matched.push({ item: policy.items[idx], amount: dmg.amount });
206	  }
207	
208	  let totalPayout = 0;
209	  for (const { item, amount } of matched) {
210	    const reimbursable = rawReimbursementForDamage(item, amount);
211	    const afterDeductible = Math.max(0, reimbursable - DEDUCTIBLE);
212	    totalPayout += afterDeductible;
213	  }
214	
215	  let finalPayout = Math.floor(totalPayout);
216	  if (finalPayout > policy.remainingCap) {
217	    finalPayout = policy.remainingCap;
218	  }
219	
220	  policy.remainingCap -= finalPayout;
221	  return finalPayout;
222	}
223	
224	export function runScenario(scenario: Scenario): { results: StepResult[] } {
225	  const results: StepResult[] = [];
226	  const policies = new Map<number, Policy>();
227	  let quoteCount = 0;
228	
229	  for (let i = 0; i < scenario.steps.length; i++) {
230	    const step = scenario.steps[i];
231	    if (step.op === 'quote') {
232	      const premium = quotePremium(step.items, scenario.customer, quoteCount);
233	      const policy = createPolicy(step.items);
234	      policies.set(i, policy);
235	      results.push({ premium });
236	      quoteCount++;
237	    } else {
238	      const policy = policies.get(step.policy);
239	      if (!policy) {
240	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
241	      }
242	      const payout = processClaim(policy, step.incident);
243	      results.push({ payout, remainingCap: policy.remainingCap });
244	    }
245	  }
246	
247	  return { results };
248	}
