120	  return total;
121	}
122	
123	function computeItemSurcharges(items: Item[]): number {
124	  // Per-item modifiers: cursed (+50% of item base), high enchantment (+30% of item base).
125	  // Components in the spec examples are plain — they have no enchantment/cursed.
126	  let surcharges = 0;
127	  for (const item of items) {
128	    if (isComponent(item.type)) continue;
129	    const base = itemBasePremium(item);
130	    if (item.cursed) surcharges += base * CURSED_SURCHARGE_RATE;
131	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD) {
132	      surcharges += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
133	    }
134	  }
135	  return surcharges;
136	}
137	
138	export function quotePremium(
139	  items: Item[],
140	  customer: Customer,
141	  contractIndex: number,
142	): number {
143	  for (const item of items) {
144	    if (!isKnownType(item.type)) {
145	      throw new Error(`Unknown item type: ${item.type}`);
146	    }
147	  }
148	
149	  const policyBase = computePolicyBasePremium(items);
150	  const itemSurcharges = computeItemSurcharges(items);
151	
152	  let premium = policyBase + itemSurcharges;
153	
154	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
155	    premium -= policyBase * LOYALTY_DISCOUNT_RATE;
156	  }
157	  // First insurance always applies (each item treated as first insurance)
158	  premium += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
159	
160	  if (contractIndex >= 1) {
161	    premium -= policyBase * FOLLOW_UP_CONTRACT_DISCOUNT_RATE;
162	  }
163	
164	  premium += PROCESSING_FEE;
165	
166	  return Math.ceil(premium);
167	}
