169	export type Policy = {
170	  items: Item[];
171	  insuranceSum: number;
172	  cap: number;
173	  remainingCap: number;
174	};
175	
176	export function createPolicy(items: Item[]): Policy {
177	  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
178	  const cap = insuranceSum * INSURANCE_CAP_MULTIPLIER;
179	  return { items: [...items], insuranceSum, cap, remainingCap: cap };
180	}
181	
182	function findItemForDamage(policy: Policy, itemType: string, usedIndices: Set<number>): number {
183	  for (let i = 0; i < policy.items.length; i++) {
184	    if (usedIndices.has(i)) continue;
185	    if (policy.items[i].type === itemType) return i;
186	  }
187	  return -1;
188	}
189	
190	function rawReimbursementForDamage(item: Item, damageAmount: number): number {
191	  // Spec: damage to items with enchantment >= 8 is reimbursed at 50% of the damage
192	  // amount; damage to dragon-material items is fully reimbursed (the default).
193	  // When both clauses apply, the 50% rule wins — so the high-enchantment check is
194	  // sufficient on its own.
195	  const isHighEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
196	  return isHighEnchant ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : damageAmount;
197	}
198	
199	export function processClaim(policy: Policy, incident: Incident): number {
200	  // Each damage entry consumes one matching policy item instance and contributes
201	  // (reimbursable - deductible, floored at 0) to the payout total.
202	  const usedIndices = new Set<number>();
203	  let totalPayout = 0;
204	
205	  for (const dmg of incident.damages) {
206	    if (dmg.amount < 0) {
207	      throw new Error(`Negative damage amount: ${dmg.amount}`);
208	    }
209	    if (!isKnownType(dmg.itemType)) {
210	      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
211	    }
212	    const idx = findItemForDamage(policy, dmg.itemType, usedIndices);
213	    if (idx === -1) {
214	      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
215	    }
216	    usedIndices.add(idx);
217	    const reimbursable = rawReimbursementForDamage(policy.items[idx], dmg.amount);
218	    totalPayout += Math.max(0, reimbursable - DEDUCTIBLE);
219	  }
220	
221	  const finalPayout = Math.min(Math.floor(totalPayout), policy.remainingCap);
222	  policy.remainingCap -= finalPayout;
223	  return finalPayout;
224	}
225	
226	export function runScenario(scenario: Scenario): { results: StepResult[] } {
227	  const results: StepResult[] = [];
228	  const policies = new Map<number, Policy>();
229	  let quoteCount = 0;
230	
231	  for (let i = 0; i < scenario.steps.length; i++) {
232	    const step = scenario.steps[i];
233	    if (step.op === 'quote') {
234	      const premium = quotePremium(step.items, scenario.customer, quoteCount);
235	      const policy = createPolicy(step.items);
236	      policies.set(i, policy);
237	      results.push({ premium });
238	      quoteCount++;
239	    } else {
240	      const policy = policies.get(step.policy);
241	      if (!policy) {
242	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
243	      }
244	      const payout = processClaim(policy, step.incident);
245	      results.push({ payout, remainingCap: policy.remainingCap });
246	    }
247	  }
248	
249	  return { results };
250	}
